package utilities

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/utilities"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type CacheUtilsProxy struct {
	utilities.UnimplementedCacheUtilsServer
	client utilities.CacheUtilsClient
}

func init() {
	proxyutil.Register(&utilities.CacheUtils_ServiceDesc, NewCacheUtilsProxy)
}
func NewCacheUtilsProxy(cc grpc.ClientConnInterface) utilities.CacheUtilsServer {
	return &CacheUtilsProxy{client: utilities.NewCacheUtilsClient(cc)}
}
func (p *CacheUtilsProxy) PurgeAccessKey(ctx context.Context, in *utilities.AccessKeyPurgeRequest) (*utilities.PurgeResult, error) {
	return proxyutil.ProxyMethod[utilities.AccessKeyPurgeRequest, utilities.PurgeResult](p.client.PurgeAccessKey)(ctx, in)
}
func (p *CacheUtilsProxy) PurgeInstallations(ctx context.Context, in *utilities.InstallationsPurgeRequest) (*utilities.PurgeResult, error) {
	return proxyutil.ProxyMethod[utilities.InstallationsPurgeRequest, utilities.PurgeResult](p.client.PurgeInstallations)(ctx, in)
}
func (p *CacheUtilsProxy) PurgeInstallation(ctx context.Context, in *utilities.InstallationPurgeRequest) (*utilities.PurgeResult, error) {
	return proxyutil.ProxyMethod[utilities.InstallationPurgeRequest, utilities.PurgeResult](p.client.PurgeInstallation)(ctx, in)
}
func (p *CacheUtilsProxy) PurgeAppVersion(ctx context.Context, in *utilities.AppVersionPurgeRequest) (*utilities.PurgeResult, error) {
	return proxyutil.ProxyMethod[utilities.AppVersionPurgeRequest, utilities.PurgeResult](p.client.PurgeAppVersion)(ctx, in)
}
func (p *CacheUtilsProxy) PurgeApp(ctx context.Context, in *utilities.AppPurgeRequest) (*utilities.PurgeResult, error) {
	return proxyutil.ProxyMethod[utilities.AppPurgeRequest, utilities.PurgeResult](p.client.PurgeApp)(ctx, in)
}
